mapper.update:
UPDATE schedule
SET state = #{scheduleReplyState},
    memo  = #{memo}
WHERE member_id = #{memberId}
    AND schedule_id = #{scheduleId}

mapper.select:
SELECT COUNT(*)
FROM schedule
WHERE trainer_id = #{trainerId}
  AND state = 'RESERVATION'
  AND start_datetime < #{request.endDateTime}
  AND end_datetime > #{request.startDateTime}
